import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import toast from 'react-hot-toast';

export default function FigmaLoginPage() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const { login } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        const success = await login(email, password);
        setLoading(false);
        if (success) navigate('/');
    };

    return (
        <div className="login-container">
            {/* Фоновое изображение - /images/figma-images/yadro_pattern_1-1-2.png */}
            <div className="login-bg">
                <img src="/images/figma-images/yadro_pattern_1-1-2.png" alt="background" className="login-bg-image" />
            </div>

            <div className="login-card">
                <div className="login-logo">
                    <div className="logo-icon">
                        <img src="/images/figma-images/vector-5.svg" alt="logo" className="logo-icon-img" />
                    </div>
                    <h1 className="login-title">VideoPlatform</h1>
                </div>

                <h2 className="login-heading">Добро пожаловать</h2>

                <form onSubmit={handleSubmit} className="login-form">
                    <div className="input-group">
                        <input
                            type="email"
                            placeholder="Email"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            className="login-input"
                            required
                        />
                    </div>

                    <div className="input-group">
                        <input
                            type="password"
                            placeholder="Пароль"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            className="login-input"
                            required
                        />
                    </div>

                    <button type="submit" disabled={loading} className="login-btn">
                        {loading ? 'Вход...' : 'Войти'}
                    </button>
                </form>

                <p className="login-footer">
                    Нет аккаунта? <Link to="/register">Регистрация</Link>
                </p>
            </div>
        </div>
    );
}
